def targets = [['asset'], ['asset','os'], ['asset','hardware'], ['m_26_14']];
def fields = [['name'], ['version','build','platform'], ['serial_number'], ['baseline_hash']];
for (int i = 0; i < targets.size(); i++) {
  def node = ctx;
  for (String seg : (List)targets[i]) {
    if (!(node instanceof Map)) { node = null; break; }
    node = ((Map)node).get(seg);
  }
  if (!(node instanceof Map)) continue;
  for (String f : (List)fields[i]) {
    def v = ((Map)node).get(f);
    if (v instanceof Map) {
      if (((Map)v).isEmpty()) { ((Map)node).remove(f); }
      else { ((Map)node)[f] = ((Map)v).keySet().iterator().next(); }
    }
  }
}
